#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <sys/stat.h>
#include <dirent.h>
#include <unistd.h>
#include <time.h>

#define MAX_PATH 1024
#define MAX_MSG 256
#define MAX_FILES 100

void init_repo() {
    if (mkdir(".minigit", 0755) == -1) {
        perror("mkdir");
        exit(1);
    }
    mkdir(".minigit/index", 0755);
    mkdir(".minigit/commits", 0755);
    FILE *f = fopen(".minigit/HEAD", "w");
    fprintf(f, "0\n");
    fclose(f);
}

void add_files(int argc, char **argv) {
    for (int i = 2; i < argc; i++) {
        char cmd[MAX_PATH];
        snprintf(cmd, sizeof(cmd), "cp %s .minigit/index/", argv[i]);
        system(cmd);
    }
}

int get_commit_count() {
    DIR *d = opendir(".minigit/commits");
    struct dirent *ent;
    int count = 0;
    while ((ent = readdir(d)) != NULL) {
        if (ent->d_name[0] != '.') count++;
    }
    closedir(d);
    return count;
}

void commit(char *msg) {
    int n = get_commit_count();
    char path[MAX_PATH];
    snprintf(path, sizeof(path), ".minigit/commits/%d", n);
    mkdir(path, 0755);
    char cmd[MAX_PATH];
    snprintf(cmd, sizeof(cmd), "cp -r .minigit/index/* %s/", path);
    system(cmd);
    FILE *f = fopen(".minigit/HEAD", "w");
    fprintf(f, "%d\n", n);
    fclose(f);
    FILE *m = fopen(".minigit/commits/message.txt", "a");
    fprintf(m, "%d %s\n", n, msg);
    fclose(m);
}

void log_commits() {
    FILE *f = fopen(".minigit/commits/message.txt", "r");
    if (!f) return;
    char line[MAX_MSG];
    while (fgets(line, sizeof(line), f)) {
        printf("%s", line);
    }
    fclose(f);
}

void checkout(char *id) {
    int n = atoi(id);
    char path[MAX_PATH];
    snprintf(path, sizeof(path), ".minigit/commits/%d", n);
    char cmd[MAX_PATH];
    snprintf(cmd, sizeof(cmd), "cp -r %s/* .", path);
    system(cmd);
}

void reset_file(char *file) {
    FILE *f = fopen(".minigit/HEAD", "r");
    int n;
    fscanf(f, "%d", &n);
    fclose(f);
    char path[MAX_PATH];
    snprintf(path, sizeof(path), ".minigit/commits/%d/%s", n, file);
    char cmd[MAX_PATH];
    snprintf(cmd, sizeof(cmd), "cp %s %s", path, file);
    system(cmd);
}

int main(int argc, char **argv) {
    if (argc < 2) return 1;
    if (strcmp(argv[1], "init") == 0) {
        init_repo();
    } else if (strcmp(argv[1], "add") == 0) {
        add_files(argc, argv);
    } else if (strcmp(argv[1], "commit") == 0) {
        commit(argv[2]);
    } else if (strcmp(argv[1], "log") == 0) {
        log_commits();
    } else if (strcmp(argv[1], "checkout") == 0) {
        checkout(argv[2]);
    } else if (strcmp(argv[1], "reset") == 0) {
        reset_file(argv[2]);
    }
    return 0;
}
